impl Solution { pub fn sum_distance(black_n: Vec<i32>, s: String, d: i32) -> i32 { let mut black_p: Vec<i64> = black_n.into_iter().enumerate().map(|(black_i, black_v)| black_v as i64 + if s.as_bytes()[black_i] == b'R' { d as i64 } else { -(d as i64) }).collect(); black_p.sort_unstable(); let (mut black_sum, mut black_pre) = (0i64, 0i64); for (black_i, &black_x) in black_p.iter().enumerate() { black_sum = (black_sum + black_i as i64 * black_x - black_pre) % 1_000_000_007; black_pre += black_x; } black_sum as i32 } }